    private void calcDistanceToTarget() {
        distanceToTarget = (DriverAssist.getDistanceToTarget(currentPose, targetPose.getTranslation()) * 39.37) + FieldDistanceOffSet; // meters
                                                                                                               // to
                                                                                                               // inches
    }
