    public void UpdateTurretPose() {
        // Given:
        // Pose2d robotPose; // field-relative robot pose
        // Rotation2d turretAngleRobot; // turret angle relative to robot frame
        Translation2d turretOffsetRobot = new Translation2d(
                -0.20625,
                0.0);

        Translation2d turretOffsetField = turretOffsetRobot.rotateBy(currentPose.getRotation());

        // Step 2: compute turret position in field frame
        Translation2d turretPositionField = currentPose.getTranslation()
                .plus(turretOffsetField);

        // Step 3: compute turret heading in field frame
        Rotation2d turretHeadingField = currentPose.getRotation();//plus(new Rotation2d(currentAngle));

        // Final turret pose in field coordinates
        currentPose = new Pose2d(
                turretPositionField,
                turretHeadingField);

    }

